import { useCallback, useState } from 'react';

import { Button, Stack } from '@onekeyhq/components';
import { AccountSelectorProviderMirror } from '@onekeyhq/kit/src/components/AccountSelector';
import { useActiveAccount } from '@onekeyhq/kit/src/states/jotai/contexts/accountSelector';
import { useHomeTokenListSnapshot } from '@onekeyhq/kit/src/states/jotai/contexts/tokenList/cells';
import { HomeTokenListProviderMirror } from '@onekeyhq/kit/src/views/Home/components/HomeTokenListProvider/HomeTokenListProviderMirror';
import { ScanQrCode } from '@onekeyhq/kit/src/views/ScanQrCode/components';
import useScanQrCode from '@onekeyhq/kit/src/views/ScanQrCode/hooks/useScanQrCode';
import { EAccountSelectorSceneName } from '@onekeyhq/shared/types';

import { Layout } from './utils/Layout';

const ScanQrCameraDemo = () => {
  const [isShow, setIsShow] = useState(false);
  return (
    <>
      <Button onPress={() => setIsShow(!isShow)}>
        {isShow ? '关闭' : '打开'}
      </Button>
      {isShow ? (
        <Stack mt={20} w={360} h={600}>
          <ScanQrCode
            handleBarCodeScanned={async (value) => {
              alert(value);
              return {};
            }}
          />
        </Stack>
      ) : null}
    </>
  );
};

const ScanQRCodeGallery = () => {
  const scanQrCode = useScanQrCode();
  const {
    activeAccount: { account },
  } = useActiveAccount({ num: 0 });
  const {
    tokens: allTokens,
    keys: allTokensKeys,
    map,
  } = useHomeTokenListSnapshot();
  const openScanQrCodeModal = useCallback(
    async (values: {
      autoExecuteParsedAction: boolean;
      qrWalletScene?: boolean;
      showProTutorial?: boolean;
    }) => {
      try {
        const result = await scanQrCode.start({
          handlers: scanQrCode.PARSE_HANDLER_NAMES.all,
          ...values,
          account,
          tokens: {
            data: allTokens,
            keys: allTokensKeys,
            map,
          },
        });
        console.log(result);
      } catch (_e) {
        console.log('用户取消扫描');
      }
    },
    [scanQrCode, account, allTokens, allTokensKeys, map],
  );
  return (
    <Layout
      getFilePath={() => __CURRENT_FILE_PATH__}
      componentName="ScanQrCode"
      elements={[
        {
          title: '命令式弹出 Modal(自动处理)',
          element: (
            <Button
              onPress={() =>
                openScanQrCodeModal({ autoExecuteParsedAction: true })
              }
            >
              打开
            </Button>
          ),
        },
        {
          title:
            '命令式弹出 Modal(不自动处理，qrWalletScene = true & showProTutorial = false)',
          element: (
            <Button
              onPress={() =>
                openScanQrCodeModal({
                  autoExecuteParsedAction: false,
                  qrWalletScene: true,
                  showProTutorial: false,
                })
              }
            >
              打开
            </Button>
          ),
        },
        {
          title:
            '命令式弹出 Modal(不自动处理，qrWalletScene = true & showProTutorial = true)',
          element: (
            <Button
              onPress={() =>
                openScanQrCodeModal({
                  autoExecuteParsedAction: false,
                  qrWalletScene: true,
                  showProTutorial: true,
                })
              }
            >
              打开
            </Button>
          ),
        },
        {
          title: '单独测试 Camera 权限等',
          element: <ScanQrCameraDemo />,
        },
      ]}
    />
  );
};

function ScanQRCodeGalleryContainer() {
  return (
    <HomeTokenListProviderMirror>
      <AccountSelectorProviderMirror
        config={{
          sceneName: EAccountSelectorSceneName.home,
        }}
        enabledNum={[0]}
      >
        <ScanQRCodeGallery />
      </AccountSelectorProviderMirror>
    </HomeTokenListProviderMirror>
  );
}

export default ScanQRCodeGalleryContainer;
